import math
import heapq

def shortest_drone_path(start, end, obstacles):
    EPS = 1e-9
    CLR = 1e-6
    PI2 = 2 * math.pi

    if math.hypot(start[0] - end[0], start[1] - end[1]) < EPS:
        return 0.0

    def seg_min_dist(x1, y1, x2, y2, cx, cy):
        dx, dy = x2 - x1, y2 - y1
        ls = dx * dx + dy * dy
        if ls < EPS * EPS:
            return math.hypot(cx - x1, cy - y1)
        t = max(0.0, min(1.0, ((cx - x1) * dx + (cy - y1) * dy) / ls))
        return math.hypot(cx - (x1 + t * dx), cy - (y1 + t * dy))

    def segment_clear(x1, y1, x2, y2):
        for cx, cy, r in obstacles:
            if seg_min_dist(x1, y1, x2, y2, cx, cy) < r - CLR:
                return False
        return True

    def angle_in_arc(theta, arc_start, arc_span):
        return CLR < (theta - arc_start) % PI2 < arc_span - CLR

    def arcs_overlap(s1, span1, s2, span2):
        if span1 < CLR or span2 < CLR:
            return False
        if span1 > PI2 - CLR or span2 > PI2 - CLR:
            return True
        for a, b, s, sp in [(s1, s1 + span1, s2, span2), (s2, s2 + span2, s1, span1)]:
            if angle_in_arc(a % PI2, s % PI2, sp):
                return True
            if angle_in_arc(b % PI2, s % PI2, sp):
                return True
        return False

    def arc_clear(acx, acy, ar, a_start, a_span, skip_idx):
        a_s = a_start % PI2
        for idx, (cx, cy, r) in enumerate(obstacles):
            if idx == skip_idx:
                continue
            dx, dy = cx - acx, cy - acy
            d = math.hypot(dx, dy)
            if d >= ar + r - CLR:
                continue
            if d < EPS:
                if ar < r - CLR:
                    return False
                continue
            cos_th = (d * d + ar * ar - r * r) / (2 * ar * d)
            if cos_th <= -1 + EPS:
                return False
            if cos_th >= 1 - EPS:
                continue
            alpha = math.acos(max(-1.0, min(1.0, cos_th)))
            phi = math.atan2(dy, dx)
            if arcs_overlap(a_s, a_span, (phi - alpha) % PI2, 2 * alpha):
                return False
        return True

    nodes = [(start[0], start[1], -1), (end[0], end[1], -1)]
    for i, (cx, cy, r) in enumerate(obstacles):
        for pt in [start, end]:
            if abs(math.hypot(pt[0] - cx, pt[1] - cy) - r) < 1e-4:
                nodes.append((pt[0], pt[1], i))
    for px, py in [start, end]:
        for i, (cx, cy, r) in enumerate(obstacles):
            dx, dy = px - cx, py - cy
            d = math.hypot(dx, dy)
            if d <= r + EPS:
                continue
            phi = math.atan2(dy, dx)
            alpha = math.acos(min(1.0, r / d))
            for sign in [1, -1]:
                theta = phi + sign * alpha
                nodes.append((cx + r * math.cos(theta), cy + r * math.sin(theta), i))
    for i in range(len(obstacles)):
        c1x, c1y, r1 = obstacles[i]
        for j in range(i + 1, len(obstacles)):
            c2x, c2y, r2 = obstacles[j]
            dx, dy = c2x - c1x, c2y - c1y
            d = math.hypot(dx, dy)
            if d < EPS:
                continue
            phi = math.atan2(dy, dx)
            val = (r1 - r2) / d
            if abs(val) <= 1 + EPS:
                val = max(-1.0, min(1.0, val))
                beta = math.acos(val)
                for sign in [1, -1]:
                    theta = phi + sign * beta
                    c, s = math.cos(theta), math.sin(theta)
                    nodes.append((c1x + r1 * c, c1y + r1 * s, i))
                    nodes.append((c2x + r2 * c, c2y + r2 * s, j))
            val = (r1 + r2) / d
            if val <= 1 + EPS:
                val = min(1.0, val)
                beta = math.acos(val)
                for sign in [1, -1]:
                    theta = phi + sign * beta
                    c, s = math.cos(theta), math.sin(theta)
                    nodes.append((c1x + r1 * c, c1y + r1 * s, i))
                    nodes.append((c2x - r2 * c, c2y - r2 * s, j))
    n = len(nodes)
    adj = [[] for _ in range(n)]
    for i in range(n):
        for j in range(i + 1, n):
            x1, y1, c1 = nodes[i]
            x2, y2, c2 = nodes[j]
            d = math.hypot(x2 - x1, y2 - y1)
            if d < EPS:
                adj[i].append((j, 0.0))
                adj[j].append((i, 0.0))
                continue
            if segment_clear(x1, y1, x2, y2):
                adj[i].append((j, d))
                adj[j].append((i, d))
            if c1 >= 0 and c1 == c2:
                cx, cy, r = obstacles[c1]
                a1 = math.atan2(y1 - cy, x1 - cx)
                a2 = math.atan2(y2 - cy, x2 - cx)
                span_ccw = (a2 - a1) % PI2
                if span_ccw > EPS:
                    if arc_clear(cx, cy, r, a1, span_ccw, c1):
                        adj[i].append((j, r * span_ccw))
                        adj[j].append((i, r * span_ccw))
                span_cw = PI2 - span_ccw
                if span_cw > EPS and span_cw < PI2 - EPS:
                    if arc_clear(cx, cy, r, a2, span_cw, c1):
                        adj[i].append((j, r * span_cw))
                        adj[j].append((i, r * span_cw))
    dist_arr = [float('inf')] * n
    dist_arr[0] = 0.0
    pq = [(0.0, 0)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist_arr[u] + EPS:
            continue
        if u == 1:
            return round(d, 6)
        for v, w in adj[u]:
            nd = d + w
            if nd < dist_arr[v] - EPS:
                dist_arr[v] = nd
                heapq.heappush(pq, (nd, v))
    return round(dist_arr[1], 6)
